768:     /// When we're looking up a method by path (UFCS), we relate the receiver
769:     /// types invariantly. When we are looking up a method by the `.` operator,
770:     /// we relate them covariantly.
771:     fn variance(&self) -> ty::Variance {
772:         match self.mode {
773:             Mode::MethodCall => ty::Covariant,
774:             Mode::Path => ty::Invariant,
775:         }
776:     }
