809:     fn assemble_probe(
810:         &mut self,
811:         self_ty: &Canonical<'tcx, QueryResponse<'tcx, Ty<'tcx>>>,
812:         receiver_steps: usize,
813:     ) {
814:         let raw_self_ty = self_ty.value.value;
815:         match *raw_self_ty.kind() {
816:             ty::Dynamic(data, ..) if let Some(p) = data.principal() => {
817:                 // Subtle: we can't use `instantiate_query_response` here: using it will
818:                 // commit to all of the type equalities assumed by inference going through
819:                 // autoderef (see the `method-probe-no-guessing` test).
820:                 //
821:                 // However, in this code, it is OK if we end up with an object type that is
822:                 // "more general" than the object type that we are evaluating. For *every*
823:                 // object type `MY_OBJECT`, a function call that goes through a trait-ref
824:                 // of the form `<MY_OBJECT as SuperTraitOf(MY_OBJECT)>::func` is a valid
825:                 // `ObjectCandidate`, and it should be discoverable "exactly" through one
826:                 // of the iterations in the autoderef loop, so there is no problem with it
827:                 // being discoverable in another one of these iterations.
828:                 //
829:                 // Using `instantiate_canonical` on our
830:                 // `Canonical<QueryResponse<Ty<'tcx>>>` and then *throwing away* the
831:                 // `CanonicalVarValues` will exactly give us such a generalization - it
832:                 // will still match the original object type, but it won't pollute our
833:                 // type variables in any form, so just do that!
834:                 let (QueryResponse { value: generalized_self_ty, .. }, _ignored_var_values) =
835:                     self.fcx.instantiate_canonical(self.span, self_ty);
836: 
837:                 self.assemble_inherent_candidates_from_object(generalized_self_ty);
838:                 self.assemble_inherent_impl_candidates_for_type(p.def_id(), receiver_steps);
839:                 self.assemble_inherent_candidates_for_incoherent_ty(raw_self_ty, receiver_steps);
840:             }
841:             ty::Adt(def, _) => {
842:                 let def_id = def.did();
843:                 self.assemble_inherent_impl_candidates_for_type(def_id, receiver_steps);
844:                 self.assemble_inherent_candidates_for_incoherent_ty(raw_self_ty, receiver_steps);
845:             }
846:             ty::Foreign(did) => {
847:                 self.assemble_inherent_impl_candidates_for_type(did, receiver_steps);
848:                 self.assemble_inherent_candidates_for_incoherent_ty(raw_self_ty, receiver_steps);
849:             }
850:             ty::Param(_) => {
851:                 self.assemble_inherent_candidates_from_param(raw_self_ty);
852:             }
853:             ty::Bool
854:             | ty::Char
855:             | ty::Int(_)
856:             | ty::Uint(_)
857:             | ty::Float(_)
858:             | ty::Str
859:             | ty::Array(..)
860:             | ty::Slice(_)
861:             | ty::RawPtr(_, _)
862:             | ty::Ref(..)
863:             | ty::Never
864:             | ty::Tuple(..) => {
865:                 self.assemble_inherent_candidates_for_incoherent_ty(raw_self_ty, receiver_steps)
